// Function to create a pseudocolor image
unsigned char* create_pseudocolor_image(unsigned char* grayscale_image, int width, int height) {
  unsigned char* pseudocolor_image = (unsigned char*)malloc(width * height * 3);
  for (int i = 0; i < width * height; i++) {
    unsigned char intensity = grayscale_image[i];
    unsigned char rgb_value[3] = {color_map[intensity][0], color_map[intensity][1], color_map[intensity][2]};
    pseudocolor_image[i * 3] = rgb_value[0];
    pseudocolor_image[i * 3 + 1] = rgb_value[1];
    pseudocolor_image[i * 3 + 2] = rgb_value[2];
  }
  return pseudocolor_image;
}

int main() {
  int width, height;
  unsigned char* grayscale_image = load_grayscale_image('image.jpg', &width, &height);
